class SecurityManager {
    private static final Map<String, User> users = new ConcurrentHashMap<>();
    private static final Map<String, String> activeSessions = new ConcurrentHashMap<>();
    private static final SecureRandom secureRandom = new SecureRandom();
    
    static {
        try {
            String salt1 = generateSalt();
            String salt2 = generateSalt();
            String salt3 = generateSalt();
            
            users.put("hr_admin", new User("hr_admin", 
                hashPassword("SecureP@ss123!", salt1), salt1, 
                new HashSet<>(Arrays.asList("HR_ADMIN", "HR_MANAGER"))));
            users.put("hr_manager", new User("hr_manager", 
                hashPassword("Manager@2024", salt2), salt2, 
                new HashSet<>(Arrays.asList("HR_MANAGER"))));
            users.put("hr_viewer", new User("hr_viewer", 
                hashPassword("Viewer@2024", salt3), salt3, 
                new HashSet<>(Arrays.asList("HR_VIEWER"))));
        } catch (Exception e) {
            throw new RuntimeException("Failed to initialize security", e);
        }
    }

    public static String authenticate(String username, String password) throws AuthenticationException {
        if (username == null || password == null || username.trim().isEmpty() || password.trim().isEmpty()) {
            throw new AuthenticationException("Invalid credentials");
        }

        User user = users.get(username);
        if (user == null) {
            try {
                Thread.sleep(100 + secureRandom.nextInt(100));
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
            throw new AuthenticationException("Invalid credentials");
        }

        try {
            String hashedPassword = hashPassword(password, user.getSalt());
            if (!MessageDigest.isEqual(hashedPassword.getBytes(), user.getPasswordHash().getBytes())) {
                throw new AuthenticationException("Invalid credentials");
            }

            String sessionToken = generateSessionToken();
            activeSessions.put(sessionToken, username);
            return sessionToken;
        } catch (Exception e) {
            throw new AuthenticationException("Authentication failed");
        }
    }

    public static void validateSession(String sessionToken) throws AuthenticationException {
        if (sessionToken == null || !activeSessions.containsKey(sessionToken)) {
            throw new AuthenticationException("Invalid or expired session");
        }
    }

    public static void authorize(String sessionToken, String requiredRole) throws AuthorizationException, AuthenticationException {
        validateSession(sessionToken);
        String username = activeSessions.get(sessionToken);
        User user = users.get(username);
        
        if (user == null || !user.getRoles().contains(requiredRole)) {
            throw new AuthorizationException("Insufficient permissions");
        }
    }

    public static void logout(String sessionToken) {
        activeSessions.remove(sessionToken);
    }

    private static String generateSalt() {
        byte[] salt = new byte[16];
        secureRandom.nextBytes(salt);
        return Base64.getEncoder().encodeToString(salt);
    }

    private static String hashPassword(String password, String salt) throws Exception {
        KeySpec spec = new PBEKeySpec(password.toCharArray(), 
            Base64.getDecoder().decode(salt), 65536, 256);
        SecretKeyFactory factory = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA256");
        byte[] hash = factory.generateSecret(spec).getEncoded();
        return Base64.getEncoder().encodeToString(hash);
    }

    private static String generateSessionToken() {
        byte[] token = new byte[32];
        secureRandom.nextBytes(token);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(token);
    }

    public static String getUsernameFromSession(String sessionToken) {
        return activeSessions.get(sessionToken);
    }
}

class InputValidator {
    private static final Pattern EMPLOYEE_ID_PATTERN = Pattern.compile("^[A-Z0-9]{6,10}$");
    private static final Pattern ALPHANUMERIC_PATTERN = Pattern.compile("^[a-zA-Z0-9\\s\\-_]{1,100}$");
    private static final Pattern COMMENT_PATTERN = Pattern.compile("^[a-zA-Z0-9\\s.,!?\\-_]{0,500}$");
    
    public static void validateEmployeeId(String employeeId) throws ValidationException {
        if (employeeId == null || !EMPLOYEE_ID_PATTERN.matcher(employeeId).matches()) {
            throw new ValidationException("Invalid employee ID format");
        }
    }

    public static void validateSalary(BigDecimal salary) throws ValidationException {
        if (salary == null || salary.compareTo(BigDecimal.ZERO) <= 0 || 
            salary.compareTo(new BigDecimal("10000000")) > 0) {
            throw new ValidationException("Invalid salary amount");
        }
    }

    public static void validateRating(int rating) throws ValidationException {
        if (rating < 1 || rating > 5) {
            throw new ValidationException("Rating must be between 1 and 5");
        }
    }

    public static void validateComments(String comments) throws ValidationException {
        if (comments != null && !COMMENT_PATTERN.matcher(comments).matches()) {
            throw new ValidationException("Invalid comments format");
        }
    }

    public static void validateString(String value, String fieldName) throws ValidationException {
        if (value == null || !ALPHANUMERIC_PATTERN.matcher(value).matches()) {
            throw new ValidationException("Invalid " + fieldName + " format");
        }
    }
}

